PRAGMA foreign_keys = ON;

-- Часть 8 из 28. Существующие тайтлы не перезаписываются.

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098958b","title":"Ходячие Мертвецы. Том 23. От шепота к крику","author":"Роберт Киркман","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002785974/140/1ae7/Robert_Kirkman__Hodyachie_Mertvetsy._Tom_23._Ot_shepota_k_kriku.jpg","isbn":"978-5-91339-637-2","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Карл теперь живёт вдали от отца в Хиллтопе, куда патруль приводит пленницу — одну из шепчущихся. Они быстро находят общий язык, и Лидия рассказывает о своём сообществе, его диких устоях и масках из кожи мёртвых. Однако когда шепчущиеся возвращаются, чтобы забрать Лидию, Мэгги совершает обмен, ведь они привели с собой пропавшего в патруле жителя Хиллтопа. Карл с этим не согласен: он пускается в путь, чтобы вернуть Лидию, в которую уже успел влюбиться.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999755,"hdCover":""},{"id":"098958a","title":"Ходячие мертвецы. Том 22. Новое начало. Выпуск 130","author":"Роберт Киркман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001102874/140/0ab6/Robert_Kirkman__Hodyachie_mertvetsy._Tom_22._Novoe_nachalo._Vypusk_130.jpg","isbn":"","publisher":"","pubDate":"","language":"Русский","series":"","genres":[],"annotation":"Красноречие не помогает Нигану, и Магна с её компаньонами удаляется, оставив узника одного. Тем временем, Рик и Карл прибывают в Хиллтоп, где Рик к своему неудовольствию обнаруживает, что вокруг него создаётся некий культ, а далеко от посёлка двое дозорных Марк и Кен пытаются спастись от толпы ходячих.  Карл осваивается на новом месте жительства, Рик и Мэгги обсуждают торговые дела, когда поступает сообщение о появлении Марка. Измождённого дозорного доставляют в лазарет, где парень в бреду рассказывает, что вынужден был оставить товарища, а главное, он слышал, как \"мертвецы разговаривают\"...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999754,"hdCover":""},{"id":"0989589","title":"Незабудка","author":"Кэндзи Цурута","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006168933/140/37d1/Kendzi_Tsuruta__Nezabudka.jpg","isbn":"978-5-905295-82-9","publisher":"Alt Graph","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"«Forget-me-not» — очаровательная жемчужина, вышедшая из-под пера Кэндзи Цуруты. Автор переносит нас на романтические улочки Венеции, где так любит гулять частный детектив Мариэль Имари. Правда, вместо расследования дел она обычно предпочитает флиртовать с юным Беппо, который работает в антикварном магазине, и подшучивать над дворецким Корнелиусом, присматривающим за особняком её дедушки Пьетро Венуччи. Имари уже давно должна была унаследовать этот особняк, но по условиям завещания для этого ей надо отыскать картину «Forget me not», украденную у господина Венуччи знаменитым вором Веккьо, который на протяжении десятилетий похищает предметы искусства и ловко водит за нос полицию. Смекалка и нестандартный подход к детективному ремеслу помогают Имари выйти на след Веккьо, и между ними начинается увлекательная игра в кошки-мышки. Манга включает в себя 7 глав, объединённых главной героиней – Мариэль Имари – потомственным сыщиком, у которой есть чёткая цель и планы на жизнь, но нет желания её реализовывать в полной мере. второстепенными героями, окружающими Мариэль и главным злодеем – таинственным вором Веккьо, который украл 30 лет назад картину из особняка дедушки Мариэль – Пьетра Венуччи. Большая часть глав повествует о разнообразных расследованиях Мариэль в роли частного сыщика. Другая часть рассказывает о противостоянии девушки и Веккьо, которые каждый раз словно призраки размениваются друг с другом при совершаемых вором ограблениях. Лишь к концу манги читатель узнает о загадочной личности вора и дальнейшей судьбе героини. Сами единичные расследования выглядят не как детективные истории Шерлока Холмса, а как комедийные приключения красивой героини с переодеваниями и развлечениями. Расследования могут оттолкнуть читателя, ожидавшего серьёзную детективную историю, на деле получившего лёгкое повествование, выраженное в поступках героев, беспечности происходящего и комедийности случаев, поистине случайных. Методы раскрытия дел Мариэль мне понравились, хоть слегка и казались пустыми и ненужными манге, но такие моменты практически полностью заполоняют всё произведение. Манга легко воспринимается при чтении, в ней нет философской мысли, как это было в «Эманон», видно, что Цурута ещё набивал руку перед своим триумфом в будущем. Рисунок всё также хорош, но, как и в случае с сюжетом, мангака подбирался к своему характерному изображению окружающего мира. Япония вышла более изобразительно и обширно в последствии у Цуруты, нежели это вышло с Венецией. Обаятельная Мариэль может влюбить себя своей бессовестной простотой и чудаковатостью. Спектр поступков девушки раскрыт неполностью, но при чтении прекрасно прослеживается беззаботность и расслабленность при любых ситуациях у Мариэль, смотря на эпизоды с её участием можно улыбнуться и удивиться такой чертой характера. Еженедельное обсуждение прочитанного в группе ВК.                                                Свернуть","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":4,"review":"","added":9999753,"hdCover":""},{"id":"0989588","title":"Ходячие мертвецы. Том 22. Новое начало","author":"Роберт Киркман","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002777190/140/2a6d/Robert_Kirkman__Hodyachie_mertvetsy._Tom_22._Novoe_nachalo.jpg","isbn":"978-5-91339-609-9","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Война уже позади, Ниган пал и теперь отбывает пожизненное заключение в тюрьме, а наши герои строят новую цивилизацию. В сообществах процветает садоводство и строительство, жители пекут хлеб, вяжут свитера и перегоняют стада ходячих. Но во время патрулирования герои встречают новую угрозу - мертвецов, которые умеют стрелять из оружия и: разговаривать!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999752,"hdCover":""},{"id":"0989587","title":"Ходячие Мертвецы. Том 21. Всеобщая война. Часть 2","author":"Роберт Киркман, Тони Мур","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002758760/140/e4a3/Robert_Kirkman_Toni_Mur__Hodyachie_Mertvetsy._Tom_21._Vseobschaya_vojna._Chast_2.jpg","isbn":"978-5-91339-595-5","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Война в полном разгаре, Ниган напал на Александрию и уничтожил линию обороны. Находясь на грани поражения, Рик предлагает Нигану мир. Обхитрив Нигана, Рик перерезает ему глотку, чтобы остановить войну между Александрией, Хиллтопом, Королевством и Спасителями. Ниган выживает и приговаривается к пожизненному заключению.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999751,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989586","title":"Ходячие мертвецы. Том 20. Всеобщая война - Часть 1. Выпуск 117","author":"Роберт Киркман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001090754/140/8e23/Robert_Kirkman__Hodyachie_mertvetsy._Tom_20._Vseobschaya_vojna__Chast_1._Vypusk_.jpg","isbn":"","publisher":"","pubDate":"2013","language":"Русский","series":"","genres":[],"annotation":"Ниган захватил в плен Холли и уверен, что она - Андреа. Холли говорит ему, что тот ошибается и упоминает о своих отношениях с Абрахамом, однако Ниган не верит ей.  Рик и Пол сидят у костра. Рик говорит ему, что волнуется о Холли, но Пол уверяет его, что с ней всё будет нормально и настаивает на том, чтобы Рик поел.  Холли связанная на базе спасителей. К ней в комнату приходит один из спасителей по имени Дэвид. После короткого разговора он начинает срывать с неё одежду. Его останавливает Ниган, напоминающий ему, что одно из их правил гласит \"мы не насилуем\". Сразу после этого Ниган бьёт его ножом в шею. Ниган затем извиняется перед Холли из-за того, что пришлось убить его у неё на глазах, но добавляет, что сделал это потому, что хотел показать, что они не чудовища.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999750,"hdCover":""},{"id":"0989585","title":"Ходячие Мертвецы. Том 20. Всеобщая война. Часть 1","author":"Роберт Киркман, Тони Мур","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002758763/140/a7b7/Robert_Kirkman_Toni_Mur__Hodyachie_Mertvetsy._Tom_20._Vseobschaya_vojna._Chast_1.jpg","isbn":"978-5-91339-590-0","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Заручившись поддержкой Хиллтопа и Королевства, Рик собирает армию и совершает нападение на Убежище. Всё идёт гладко, Ниган оказывается в ловушке в собственном доме, но после нападения на аванпосты, близкие друзья Рика начинают погибать. Возможно, их первая победа была чистой удачей. В конце концов Ниган предпринимает ответное нападение на Александрию и всё становится только хуже.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999749,"hdCover":""},{"id":"0989584","title":"Ходячие мертвецы. Том 19. Маршем на войну","author":"Роберт Киркман, Тони Мур,Роберт Киркман, Чарли Адлард, Клифф Ратбёрн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002729545/140/36aa/__Hodyachie_mertvetsy._Tom_19._Marshem_na_vojnu.jpg","isbn":"978-5-91339-585-6","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Недавние жуткие события породили множество мыслей в головах тех, кто их пережил. За ошибки и просчёты уже уплачена страшная цена, и нужно сделать так, чтобы всё это было не зря. Зима никого не щадит, для неё все равны, и наши герои прекрасно это знают. Чтобы пережить надвигающиеся холода, им понадобятся припасы, но каков шанс найти еду в уже давно опустошённых городах? Всё, что остаётся - это стать лучше. Сплотиться. Ведь один в поле не воин, если это поле кишит бездушными голодными зомби.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-11","rating":5,"review":"","added":9999748,"hdCover":""},{"id":"0989583","title":"Скитания Эманон. Том 3","author":"Синдзи Кадзио,Кэндзи Цурута","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005700267/140/25e8/__Skitaniya_Emanon._Tom_3.jpg","isbn":"978-5-905295-76-8","publisher":"Alt Graph","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"После событий второго тома прошло более 15 лет. У Эмы подрастает дочка Эико, у которой просто феноменальная память, хотя у матери всегда были с этим проблемы. На пороге взросления Эико понимает, что скоро ей придётся повторить судьбу Эмы. Несмотря ни на что Эико прислушивается только к своему внутреннему голосу, который толкает её по пути семейных секретов, старых воспоминаний и неведомого ей самой предназначения.  «Скитания Эманон» — манга-адаптация популярных научно-фантастических рассказов Синдзи Кадзио. Манга-версию нарисовал Кэндзи Цурута, разработавший свой хорошо узнаваемый стиль иллюстрации, который так хорошо наложился на сюжеты оригинальных рассказов, что теперь образ Эманон прочно связан с работами Цуруты.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-10","rating":4.5,"review":"","added":9999747,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989582","title":"Скитания Эманон. Том 2","author":"Синдзи Кадзио,Кэндзи Цурута","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005700264/140/cbf7/__Skitaniya_Emanon._Tom_2.jpg","isbn":"978-5-905295-75-1","publisher":"Alt Graph","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В 1973 году молодой писатель Рёдзо, путешествуя по горам на юге Японии, сталкивается с незнакомкой, которая не помнит абсолютно ничего о себе, а с собой у неё лишь сумка с инициалами E.N. Девушку преследуют кошмары о событиях, происходивших эоны лет назад, и она пытается сбежать от них, начав новую — тихую и размеренную — жизнь с Рёдзо. И когда, казалось бы, наконец-то всё наладилось, прошлое настигает её.  «Скитания Эманон» — манга-адаптация популярных научно-фантастических рассказов Синдзи Кадзио. Манга-версию нарисовал Кэндзи Цурута, разработавший свой узнаваемый стиль иллюстрации, который так хорошо наложился на сюжеты оригинальных рассказов, что теперь образ Эманон прочно связан с работами Цуруты.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-10","rating":4.5,"review":"","added":9999746,"hdCover":""},{"id":"0989581","title":"Ходячие Мертвецы. Том 18. Что будет дальше","author":"Роберт Киркман, Тони Мур,Роберт Киркман, Чарли Адлард, Клифф Ратбёрн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002723519/140/c22b/__Hodyachie_Mertvetsy._Tom_18._Chto_budet_dalshe.jpg","isbn":"978-5-91339-578-8","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-10","rating":5,"review":"","added":9999745,"hdCover":""},{"id":"0989580","title":"Ходячие Мертвецы. Том 17. Повод для страха","author":"Роберт Киркман, Чарли Адлард, Клифф Ратбёрн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002702753/140/50c0/Robert_Kirkman_Charli_Adlard_Kliff_Ratbjorn__Hodyachie_Mertvetsy._Tom_17._Povod_.jpg","isbn":"978-5-91339-575-7","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Недавние жуткие события породили множество мыслей в головах тех, кто их пережил. За ошибки и просчёты уже уплачена страшная цена, и нужно сделать так, чтобы всё это было не зря. Зима никого не щадит, для неё все равны, и наши герои прекрасно это знают. Чтобы пережить надвигающиеся холода, им понадобятся припасы, но каков шанс найти еду в уже давно опустошённых городах? Всё, что остаётся - это стать лучше. Сплотиться. Ведь один в поле не воин, если это поле кишит бездушными голодными зомби.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-10","rating":5,"review":"","added":9999744,"hdCover":""},{"id":"098957f","title":"Ходячие мертвецы. Том 16. Большой мир","author":"Роберт Киркман, Чарли Адлард, Клифф Ратбёрн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002688753/140/0c50/Robert_Kirkman_Charli_Adlard_Kliff_Ratbjorn__Hodyachie_mertvetsy._Tom_16._Bolsho.jpg","isbn":"978-5-91339-567-2","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Недавние жуткие события породили множество мыслей в головах тех, кто их пережил. За ошибки и просчёты уже уплачена страшная цена, и нужно сделать так, чтобы всё это было не зря. Зима никого не щадит, для неё все равны, и наши герои прекрасно это знают. Чтобы пережить надвигающиеся холода, им понадобятся припасы, но каков шанс найти еду в уже давно опустошённых городах? Всё, что остаётся — это стать лучше. Сплотиться. Ведь один в поле не воин, если это поле кишит бездушными голодными зомби.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-10","rating":5,"review":"","added":9999743,"hdCover":""},{"id":"098957e","title":"Скитания Эманон. Том 1","author":"Синдзи Кадзио,Кэндзи Цурута","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005700258/140/f95c/__Skitaniya_Emanon._Tom_1.jpg","isbn":"978-5-905295-74-4","publisher":"Alt Graph","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Девушка без имени, Эманон, скитается по Японии 1960-х годов, странствует от одного городка к другому и делится историями с теми, кто готов её выслушать. Может быть, поверить в них совсем непросто, зато они всегда поражают воображение случайных знакомых Эманон. Она одинока и нигде не задерживается надолго, ведомая лишь внутренним голосом, который зовёт её в дальние странствия.  «Скитания Эманон» — манга-адаптация популярных научно-фантастических рассказов Синдзи Кадзио. Манга-версию нарисовал Кэндзи Цурута, разработавший свой хорошо узнаваемый стиль иллюстрации, который так хорошо наложился на сюжеты оригинальных рассказов, что теперь образ Эманон прочно связан с работами Цуруты.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-10","rating":5,"review":"","added":9999742,"hdCover":""},{"id":"098957d","title":"Ходячие Мертвецы. Том 15. Мы обретаем себя","author":"Роберт Киркман, Тони Мур,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002629148/140/379a/__Hodyachie_Mertvetsy._Tom_15._My_obretaem_sebya.jpg","isbn":"978-5-91339-561-0","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Недавние жуткие события породили множество мыслей в головах тех, кто их пережил. За ошибки и просчёты уже уплачена страшная цена, и нужно сделать так, чтобы всё это было не зря. Зима никого не щадит, для неё все равны, и наши герои прекрасно это знают. Чтобы пережить надвигающиеся холода, им понадобятся припасы, но каков шанс найти еду в уже давно опустошённых городах? Всё, что остаётся — это стать лучше. Сплотиться. Ведь один в поле не воин, если это поле кишит бездушными голодными зомби.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-10","rating":4.5,"review":"","added":9999741,"hdCover":""},{"id":"098957c","title":"Ходячие мертвецы. Том 14. Безысходность","author":"Роберт Киркман,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002557090/140/cee3/__Hodyachie_mertvetsy._Tom_14._Bezyshodnost.jpg","isbn":"978-5-91339-553-5","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Говорят, природа всегда найдёт выход, но в этом мире уже давно всё встало с ног на голову. Теперь здесь царят бездумные оголодавшие зомби, и они готовы забрать своё. Чтобы противостоять такой стихии, нужно нечто покрепче ворот и заборов. Нашим героям, запертым в стенах наедине со своими тревогами, снова предстоит свидание со смертью, и только сильные духом и телом его переживут. Главное в борьбе за жизнь - не потерять себя и сохранить рассудок.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-10","rating":5,"review":"","added":9999740,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098957b","title":"Бычий Цепень","author":"Владислав Погадаев,Евгения Чащина","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003454217/140/70c7/__Bychij_Tsepen.jpg","isbn":"978-5-91339-869-7","publisher":"MOLOT HardCorp","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"История стара как мир. Что, если от рождения ты не такой, как все, пугающий ребенок со странными талантами и не самым приятным внешним видом? Страх и непонимание станут твоим окружением, а одиночество заполнит тебя изнутри. Люди боятся и ненавидят то, чего не понимают, — это в нашей природе.  Жизнь-трагедия \"ненужного\" ребенка, брошенного от рождения и воспитанного в семье юродивых людей. Он навсегда один, с кровавым следом позади и безнадегой в глазах — в грязном, невыносимом своем обреченном путешествии по глухому миру русской глубинки. Местами смутный и запутанный сюжет, но в общей сложности весьма приятно построена цепь повествования (некоторые моменты сюжета могут быть опущены и оставлены без ответа, но на общее впечатление они никак не влияют). Сама по себе интересная история, повествующая о процессе взросления ребёнка в неблагополучной семье, в плохих условиях проживания, выраженных в физическом и социальном окружении. Главный герой обладает врождённой генетической особенностью – тентаклями, разросшимися по всему телу. Мальчик рос, не получая ни образования, ни примитивных форм обучения, он просто существовал и выполнял базовые функции для поддержания жизни. В общем, не имея ничего для развития личности, герой вырос отшельником. Сложно представить таких людей в современном мире, но и такие встречаются. Им сложно адаптироваться, что практически и невозможно сделать в их ситуации. положение может усугубляться с каждой новой встречей с другими людьми или даже животными. В данном комиксе Иван проходит все стадии развития один.Интересно показаны некоторые эпизоды в жизни мальчика, например, \"светлая\" история в его жизни (художница передаёт всю суть доброты и впечатлительности мальчика, когда он заходит в дом к незнакомому деду после побега от обидчиков, путём колоринга. Она изображает дом деда как что-то доброе и чувственное, способное к ласке и пониманию, что для мальчика очень необходимо. Когда весь его окружающий мир выглядит безумно чёрно, герой не видит ничего доброго и нужного для себя. Сцена разговора хорошо запоминается как в художественном плане, так и в сценарном. Диалог героев запомнится надолго и будет служить подводкой к будущим действиям Вани). Герой вдохновляется словами своего спасителя о том, что бездействие – худшее из возможного, лучше сделать нечто ужасное, но в этом можно найти и плюсы. Далее история набирает обороты, читателя знакомят с более поздним периодом жизни, с повзрослевшем Ваней. История хорошо запоминается, а финал способствует этому, оставляя читателю крутой клиффхенгер. Отдельно хочется отметить работу художницы – Евгении Чащиной. Её стиль мне очень понравился, грязные элементы, неаккуратные детали акцентируют внимание. Мне напомнил стиль рисунка Бена Темплсмита. Хорошо проработанный колоринг: уходящие в черноту болота и картины быта жителей. леттеринг (Кирилла Смолина) – шрифт схож с тентаклями главного героя, также небрежно то опускающимися, то разрастающимися буквами.Рекомендую к ознакомлению тем, кто не боится попробовать что-то новое или уже знаком с похожими работами, например, «Фелл» Эллиса и Темплсмита. Довольно неординарная работа, которая может понравиться своей утончённостью в проработке персонажей и окружающей действительности, от которой берёт в дрожь. Еженедельное обсуждение прочитанного в группе ВК.                                                Свернуть","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":4,"review":"","added":9999739,"hdCover":""},{"id":"098957a","title":"Ходячие Мертвецы. Том 13. Нет пути назад","author":"Роберт Киркман, Чарли Адлард, Клифф Ратбёрн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002472571/140/c4a9/Robert_Kirkman_Charli_Adlard_Kliff_Ratbjorn__Hodyachie_Mertvetsy._Tom_13._Net_pu.jpg","isbn":"978-5-91339-543-6","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Мы продолжаем следить за жизнью героев, которые после долгих скитаний находят новых выживших и обретают кров над головой. Терзания не покидают их мысли, ведь новые люди – это не только новые возможности, но и потенциальные неприятности. Как после пережитых лишений снова довериться незнакомцам? Кто теперь возглавит группу? И как избежать повторения жутких тюремных событий?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":5,"review":"","added":9999738,"hdCover":""},{"id":"0989579","title":"Ходячие Мертвецы. Том 12. Жизнь среди них","author":"Роберт Киркман, Тони Мур,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002348392/140/be6b/__Hodyachie_Mertvetsy._Tom_12._Zhizn_sredi_nih.jpg","isbn":"978-5-91339-533-7","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Уже целый год прошёл с момента, как мёртвые начали ходить по земле. Судьба сталкивает героев с остатками прошлой жизни, возлагая тяжким грузом воспоминания на их ещё не окрепшие после трагедии плечи. Это становится настоящим испытанием, ведь многие, кого они знали прежде, уже утратили свою человечность, вынужденные приспосабливаться в новом мире. Одичавшее общество диктует свои условия, готовы ли наши выжившие их принять?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":5,"review":"","added":9999737,"hdCover":""},{"id":"0989578","title":"Ходячие Мертвецы. Том 11. Бойтесь охотников","author":"Роберт Киркман, Тони Мур,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002267225/140/2169/__Hodyachie_Mertvetsy._Tom_11._Bojtes_ohotnikov.jpg","isbn":"978-5-91339-515-3","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Уже целый год прошёл с момента, как мёртвые начали ходить по земле. Судьба сталкивает героев с остатками прошлой жизни, возлагая тяжким грузом воспоминания на их ещё не окрепшие после трагедии плечи. Это становится настоящим испытанием, ведь многие, кого они знали прежде, уже утратили свою человечность, вынужденные приспосабливаться в новом мире. Одичавшее общество диктует свои условия, готовы ли наши выжившие их принять?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":5,"review":"","added":9999736,"hdCover":""}]');

