  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989577","title":"Ходячие мертвецы. Том 10. Чем мы стали","author":"Роберт Киркман, Тони Мур,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002213760/140/ce62/__Hodyachie_mertvetsy._Tom_10._Chem_my_stali.jpg","isbn":"978-5-91339-504-7","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Уже целый год прошел с момента, как мертвые начали ходить по земле. Судьба сталкивает героев с остатками прошлой жизни, возлагая тяжким грузом воспоминания на их еще не окрепшие после трагедии плечи. Это становится настоящим испытанием, ведь многие, кого они знали прежде, уже утратили свою человечность, вынужденные приспосабливаться в новом мире. Одичавшее общество диктует свои условия, готовы ли наши выжившие их принять?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":4.5,"review":"","added":9999735,"hdCover":""},{"id":"0989576","title":"Ходячие Мертвецы. Том 9. Жизнь продолжается","author":"Роберт Киркман, Тони Мур,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002173641/140/a808/__Hodyachie_Mertvetsy._Tom_9._Zhizn_prodolzhaetsya.jpg","isbn":"978-5-91339-458-3","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Ничто не может длиться вечно. Опустошённые и выбитые из привычного русла, наши герои собирают жизнь по осколкам. Что теперь делать, куда идти? Вопросы, казалось бы, уже давно не актуальные, снова встают ребром, уменьшая ничтожные шансы сохранить рассудок. Как после всех потерь, смертей и разрушений набраться сил и жить дальше?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":4.5,"review":"","added":9999734,"hdCover":""},{"id":"0989575","title":"Ходячие Мертвецы. Том 8. Обреченные страдать","author":"Роберт Киркман, Тони Мур,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002120774/140/2fd2/__Hodyachie_Mertvetsy._Tom_8._Obrechennye_stradat.jpg","isbn":"978-5-91339-491-0","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Людское безумие и жестокость в мире зомби уже давно не знают предела, и нельзя сказать точно, кто из любимых и почти что родных героев выживет в схватке с неизбежным злом. Для кого из них восьмой том станет последним?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":5,"review":"","added":9999733,"hdCover":""},{"id":"0989574","title":"Ходячие мертвецы. Том 8: Рожденные Страдать. Выпуск 48","author":"Роберт Киркман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1000958347/140/86e0/Robert_Kirkman__Hodyachie_mertvetsy._Tom_8_Rozhdennye_Stradat._Vypusk_48.jpg","isbn":"","publisher":"","pubDate":"2008","language":"Русский","series":"","genres":[],"annotation":"В своей комнате Рик обнаруживает, что Элис держит Лори и Джудит на прицеле. Рик шокирован, но затем Лори объясняет, что это была мера предосторожности. Если бы в тюрьму ворвались выжившие из Вудбери, то Элис притворилась бы, что она помогает им взять Лори в заложники.  Брайан Блейк находится снаружи с большой группой солдат Вудбери. Он приказывает им стрелять по Хершелу, Билли и Патриции, укрывающимся за углом здания. Патриция говорит, что они умрут, если будут просто сидеть на месте и обращается в бегство, Билли пытается остановить её, но Патрицию тут же убивает выстрел кого-то из солдат Вудбери. Билли не может пошевелиться под впечатлением от смерти Патриции, но Хершел хватает его и говорит, что нет времени на то, что бы быть шокированным. Они бегут к грузовику, но пуля попадает в голову Билли.  Семья Граймс и Элис выходят наружу и видят, что Хершел стоит на коленях над телом сына. Рик зовет Хершела и это помогает Губернатору определить их местоположение. Хершел отказывается последовать за ними. Элис открывает огонь по выжившим из Вудбери чтобы прикрыть бегство семьи Граймсов. Пуля попадает ей в колено и она падает. Она успевает застрелить еще одного из солдат Губернатора, но затем Губернатор ее обезоруживает и убивает в упор.  Карл, Рик и Лори продолжают бежать. Губернатор отдает приказ Лилли стрелять по ним. Она попадает из дробовика в Лори. Лори падает и своим весом раздавливает Джудит. Рик кричит Карлу не оглядываться и продолжать бежать. Вместо того, чтобы бежать к грузовику Рик и Карл бегут в проем в ограде и пробиваются через толпу зомби. Губернатор дает им уйти полагая, что они долго не продержатся вне стен. Затем Губернатор поворачивается к склонившемуся над Билли Хершелу и убивает его выстрелом в голову.  Лилли осознает, что она только что убила младенца и поворачивается к Губернатору. Она называет его чудовищем и бьет его прикладом дробовика и вставляет ствол ему в рот. Другие выжившие из Вудбери кричат ей, чтобы она остановилась. Зомби тем временем прорываются внутрь двора тюрьмы и группа Вудбери оказывается в ловушке. Губернатор вынимает ствол дробовика изо рта и пытается успокоить группу, но Лилли стреляет ему в голову и бросает тело на растерзание наступающим зомби. Оставшиеся выжившие из Вудбери стреляя на бегу, скрываются в здании тюрьмы. У них заканчиваются патроны как раз когда они успевают укрыться в здании.  После бегства из тюрьмы Карл спрашивает где мама и Джудит. Рик начинает плакать и пытается объяснить, но не может. Выпуск заканчивается общим планом показывающим тюрьму с поваленной оградой и зомби заполнившими периметр.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":5,"review":"","added":9999732,"hdCover":""},{"id":"0989573","title":"Омон Ра. Графический роман","author":"Виктор Пелевин,Аскольд Акишин,Кирилл Кутузов","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002890541/140/8fce/__Omon_Ra._Graficheskij_roman.jpg","isbn":"978-5-91339-723-2","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Комильфо. Комиксы русских авторов","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"Графическая адаптация культового романа Виктора Пелевина, выполненная мэтром отечественного графического романа Аскольдом Акишиным и знатоком комиксов Кириллом Кутузовым, отправит нас прямо в советское прошлое, в котором вся страна грезила полётами в далёкий космос, а каждый первый мальчишка мечтал стать космонавтом. Главный герой Омон решил не останавливаться на мечтах и поступил в лётное училище имени Маресьева, а там... Там реальность переплетается с мифом, героя окружают видения и химеры, вопреки которым человек с именем Омон и позывным Ра должен покорить космос...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":4.5,"review":"","added":9999731,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989572","title":"Ходячие мертвецы. Том 7. Затишье перед…","author":"Роберт Киркман,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002058208/140/1f56/__Hodyachie_mertvetsy._Tom_7._Zatishe_pered.jpg","isbn":"978-5-91339-478-1","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"После мрачных событий шестого тома наши герои получают небольшую передышку. Время прийти в себя, собраться с мыслями, залечить раны и наладить отношения внутри коллектива.  В такие моменты очень легко забыть об опасности и начать наслаждаться жизнью. Но мёртвые не спят. Их ли стоит бояться нашим выжившим? Или есть в мире пост-апокалипсиса что-то пострашнее, чем ожившие трупы? Неужели это чувство защищённости — просто иллюзия, всего лишь затишье перед... бурей?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":5,"review":"","added":9999730,"hdCover":""},{"id":"0989571","title":"Ходячие мертвецы. Том 6. Эта горестная жизнь","author":"Роберт Киркман, Тони Мур,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002026082/140/a2d3/__Hodyachie_mertvetsy._Tom_6._Eta_gorestnaya_zhizn.jpg","isbn":"978-5-91339-464-4","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Один из главных комиксов последнего десятилетия - хит продаж, любимец критиков, любимая серия миллионов. Сегодня \"Ходячие мертвецы\" - это еще и сверхпопулярный сериал и невероятно успешная видеоигра, но сначала был комикс.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":5,"review":"","added":9999729,"hdCover":""},{"id":"0989570","title":"Ходячие Мертвецы. Том 5. Лучшая защита","author":"Роберт Киркман,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002006216/140/7791/__Hodyachie_Mertvetsy._Tom_5._Luchshaya_zaschita.jpg","isbn":"978-5-91339-455-2","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Один из главных комиксов последнего десятилетия - хит продаж, любимец критиков, любимая серия миллионов. Сегодня \"Ходячие мертвецы\" - это еще и сверхпопулярный сериал и невероятно успешная видеоигра, но сначала был комикс.  Сколько часов в день вы не тратите, просиживая перед телевизором?  Когда в последний раз кто-нибудь из нас на самом деле старался, чтобы получить желаемое?  Давно ли кому-то из нас действительно было нужно то, чего мы постоянно хотим?  Мир, который мы знали, исчез.  На смену миру торговли и пустого потребительства пришел мир выживания и ответственности.  Эпидемия апокалиптических масштабов прокатилась по планете, пробудив мёртвых, которые начали пожирать живых. За несколько месяцев человеческое общество было разрушено. Исчезли правительства, магазины, доставка почты, кабельное телевидение.  В мире, где правят мёртвые, мы наконец вынуждены начать жить.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":5,"review":"","added":9999728,"hdCover":""},{"id":"098956f","title":"Ходячие Мертвецы. Том 4. Веление сердца","author":"Роберт Киркман, Чарли Адлард, Клифф Ратбёрн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002011763/140/21b6/Robert_Kirkman_Charli_Adlard_Kliff_Ratbjorn__Hodyachie_Mertvetsy._Tom_4._Velenie.jpg","isbn":"978-5-91339-454-5","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Один из главных комиксов последнего десятилетия - хит продаж, любимец критиков, любимая серия миллионов. Сегодня \"Ходячие мертвецы\" - это еще и сверхпопулярный сериал и невероятно успешная видеоигра, но сначала был комикс. #19-24.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-09","rating":5,"review":"","added":9999727,"hdCover":""}]');
